const projects = $('Fetch All Projects DB1').all().map(i => i.json);
const tasks = $('Fetch All Tasks DB3').all().map(i => i.json);
const vulns = $('Fetch All Vulns DB5').all().map(i => i.json);

const phaseOrder = ['Pre-Kickoff','Kickoff','Initial Test','Initial Report','Presentation','Patching','Retest','Retest Report'];
const phaseDateMap = {
  'Pre-Kickoff': 'date_pre_kickoff',
  'Kickoff': 'date_kickoff',
  'Initial Test': 'date_initial_test',
  'Initial Report': 'date_initial_report',
  'Presentation': 'date_presentation',
  'Patching': 'date_patching',
  'Retest': 'date_retest',
  'Retest Report': 'date_retest_report'
};

function getProp(props, key, type) {
  const p = props[key];
  if (!p) return null;
  if (type === 'title') return p.title?.[0]?.plain_text || null;
  if (type === 'text') return p.rich_text?.[0]?.plain_text || null;
  if (type === 'select') return p.select?.name || null;
  if (type === 'multi_select') return p.multi_select?.map(s => s.name) || [];
  if (type === 'date') return p.date?.start || null;
  if (type === 'number') return p.number || 0;
  if (type === 'relation') return p.relation?.map(r => r.id) || [];
  return null;
}

function calcStatus(project) {
  const props = project.properties || {};
  const today = new Date();
  const currentPhase = getProp(props, 'current_phase', 'select');
  if (!currentPhase) return 'Pre-Engagement';
  if (currentPhase === 'Retest Report') {
    const d = getProp(props, 'date_retest_report', 'date');
    if (d && today > new Date(d)) return 'Finish';
  }
  const dateField = phaseDateMap[currentPhase];
  if (dateField) {
    const d = getProp(props, dateField, 'date');
    if (d && today > new Date(d)) return 'Delay';
  }
  if (currentPhase === 'Pre-Kickoff') return 'Pre-Engagement';
  return 'On Going';
}

const projectSummaries = projects.map(proj => {
  const props = proj.properties || {};
  const projectId = proj.id;
  const status = calcStatus(proj);
  const projTasks = tasks.filter(t => {
    const rel = t.properties?.project_id?.relation || [];
    return rel.some(r => r.id === projectId);
  });
  const projVulns = vulns.filter(v => {
    const rel = v.properties?.project_id?.relation || [];
    return rel.some(r => r.id === projectId);
  });
  const taskStats = {
    total: projTasks.length,
    not_started: projTasks.filter(t => getProp(t.properties, 'task_status', 'select') === 'Not Started').length,
    in_progress: projTasks.filter(t => getProp(t.properties, 'task_status', 'select') === 'In Progress').length,
    blocked: projTasks.filter(t => getProp(t.properties, 'task_status', 'select') === 'Blocked').length,
    done: projTasks.filter(t => getProp(t.properties, 'task_status', 'select') === 'Done').length
  };
  const vulnStats = {
    total: projVulns.length,
    critical: projVulns.filter(v => getProp(v.properties, 'severity', 'select') === 'Critical').length,
    high: projVulns.filter(v => getProp(v.properties, 'severity', 'select') === 'High').length,
    medium: projVulns.filter(v => getProp(v.properties, 'severity', 'select') === 'Medium').length,
    low: projVulns.filter(v => getProp(v.properties, 'severity', 'select') === 'Low').length,
    open: projVulns.filter(v => getProp(v.properties, 'status', 'select') === 'Open').length,
    patched: projVulns.filter(v => getProp(v.properties, 'status', 'select') === 'Patched').length,
    retest_passed: projVulns.filter(v => getProp(v.properties, 'status', 'select') === 'Retest Passed').length
  };
  return {
    project_id: getProp(props, 'project_id', 'title'),
    project_name: getProp(props, 'project_name', 'text'),
    client_name: getProp(props, 'client_name', 'text'),
    methodology: getProp(props, 'methodology', 'select'),
    current_phase: getProp(props, 'current_phase', 'select'),
    status,
    pm_notes: getProp(props, 'pm_notes', 'text'),
    objects: getProp(props, 'object_list', 'multi_select'),
    date_retest_report: getProp(props, 'date_retest_report', 'date'),
    task_stats: taskStats,
    vuln_stats: vulnStats
  };
});

const summaryMode = $input.first().json.summary_mode || 'full';
const totalProjects = projectSummaries.length;
const activeProjects = projectSummaries.filter(p => p.status !== 'Finish').length;
const delayedProjects = projectSummaries.filter(p => p.status === 'Delay').length;

return [{
  json: {
    projects: projectSummaries,
    meta: { totalProjects, activeProjects, delayedProjects, summaryMode, generatedAt: new Date().toISOString() },
    target_chat_id: $input.first().json.target_chat_id
  }
}];

const summaryText = $input.first().json.text || 'Tidak dapat generate summary saat ini.';
const meta = $('Aggregate Project Data').first().json.meta;
const targetChatId = $('Aggregate Project Data').first().json.target_chat_id;

const header = `📊 <b>LAPORAN PROYEK VAPT</b>\n🕐 ${new Date().toLocaleString('id-ID', {timeZone:'Asia/Jakarta'})} WIB\n`;
const fullText = header + '\n' + summaryText;

// Split if > 4096 chars (Telegram limit)
const MAX_LEN = 4000;
const messages = [];
if (fullText.length <= MAX_LEN) {
  messages.push(fullText);
} else {
  let remaining = fullText;
  while (remaining.length > 0) {
    let chunk = remaining.substring(0, MAX_LEN);
    const lastNewline = chunk.lastIndexOf('\n');
    if (lastNewline > 0) chunk = remaining.substring(0, lastNewline);
    messages.push(chunk);
    remaining = remaining.substring(chunk.length);
  }
}

return messages.map((msg, idx) => ({ json: { text: msg, chat_id: targetChatId, part: idx + 1, total_parts: messages.length } }));
